//! Parity tests: Rust vs Python numerical equivalence.
//!
//! Component tests use hardcoded expected values derived from the same formula.
//! JSON-driven tests load tests/vectors.json (generated by tools/gen_test_vectors.py).
//! If vectors.json is absent, JSON-driven tests are silently skipped.
//!
//! Run all:  cargo test -p needle-core
//! Run one:  cargo test -p needle-core test_zc_rms_norm

use needle_core::attn::{AttnWeights, KvCache};
use needle_core::config::TransformerConfig;
use needle_core::layers::{DecoderLayer, EncoderLayer};
use needle_core::model::NeedleModel;
use needle_core::norm::zc_rms_norm_vec;
use needle_core::quant::QuantizedWeight;
use needle_core::rope::RopeCache;

const TOL: f32 = 1e-5;

fn assert_close(got: &[f32], want: &[f32], label: &str) {
    assert_eq!(got.len(), want.len(), "{label}: length mismatch");
    for (i, (g, w)) in got.iter().zip(want.iter()).enumerate() {
        let diff = (g - w).abs();
        assert!(
            diff < TOL,
            "{label}[{i}]: got {g:.8} want {w:.8} diff {diff:.2e}",
        );
    }
}

fn load_vectors() -> Option<serde_json::Value> {
    let path = concat!(env!("CARGO_MANIFEST_DIR"), "/../../tests/vectors.json");
    let data = std::fs::read_to_string(path).ok()?;
    serde_json::from_str(&data).ok()
}

fn json_f32_vec(v: &serde_json::Value) -> Vec<f32> {
    v.as_array()
        .unwrap()
        .iter()
        .map(|n| n.as_f64().unwrap() as f32)
        .collect()
}

/// Recursively flatten a nested JSON array of numbers into a flat Vec<f32>.
fn json_f32_flat(v: &serde_json::Value) -> Vec<f32> {
    let mut out = Vec::new();
    flatten_val(v, &mut out);
    out
}

fn flatten_val(v: &serde_json::Value, out: &mut Vec<f32>) {
    match v {
        serde_json::Value::Array(arr) => {
            for item in arr {
                flatten_val(item, out);
            }
        }
        serde_json::Value::Number(n) => out.push(n.as_f64().unwrap() as f32),
        _ => {}
    }
}

// ── ZCRMSNorm — hardcoded ────────────────────────────────────────────────────

#[test]
fn test_zc_rms_norm_zero_scale() {
    let x_in = [1.0f32, 2.0, 3.0, 4.0];
    let scale = [0.0f32; 4];

    let mean_sq: f32 = x_in.iter().map(|v| v * v).sum::<f32>() / 4.0;
    let inv = 1.0 / (mean_sq + 1e-6f32).sqrt();
    let want: Vec<f32> = x_in.iter().map(|&v| v * inv).collect();

    let mut x = x_in.to_vec();
    zc_rms_norm_vec(&mut x, &scale);
    assert_close(&x, &want, "zc_rms_norm zero_scale");
}

#[test]
fn test_zc_rms_norm_nonzero_scale() {
    let x_in = [1.0f32, 2.0, 3.0, 4.0];
    let scale = [0.1f32, -0.2, 0.3, -0.4];

    let mean_sq: f32 = x_in.iter().map(|v| v * v).sum::<f32>() / 4.0;
    let inv = 1.0 / (mean_sq + 1e-6f32).sqrt();
    let want: Vec<f32> = x_in
        .iter()
        .zip(scale.iter())
        .map(|(&v, &s)| (1.0 + s) * v * inv)
        .collect();

    let mut x = x_in.to_vec();
    zc_rms_norm_vec(&mut x, &scale);
    assert_close(&x, &want, "zc_rms_norm nonzero_scale");
}

#[test]
fn test_zc_rms_norm_eps_inside_sqrt() {
    let x_in = [1e-4f32; 4];
    let scale = [0.0f32; 4];

    let mean_sq: f32 = x_in.iter().map(|v| v * v).sum::<f32>() / 4.0;
    let inv_correct = 1.0 / (mean_sq + 1e-6f32).sqrt();
    let want: Vec<f32> = x_in.iter().map(|&v| v * inv_correct).collect();

    let mut x = x_in.to_vec();
    zc_rms_norm_vec(&mut x, &scale);
    assert_close(&x, &want, "eps_inside_sqrt");

    assert!(
        x[0] < 1.0,
        "eps must be inside sqrt — output should be ~0.1, not ~9.9"
    );
}

// ── RoPE — hardcoded ─────────────────────────────────────────────────────────

#[test]
fn test_rope_identity_at_pos0() {
    let head_dim = 4;
    let rope = RopeCache::new(8, head_dim, 10000.0);

    let orig = vec![1.0f32, 2.0, 3.0, 4.0];
    let mut q = orig.clone();
    rope.apply(&mut q, 1, 1, head_dim, 0);
    assert_close(&q, &orig, "rope_identity_pos0");
}

#[test]
fn test_rope_pos1_head_dim4() {
    let head_dim = 4;
    let rope = RopeCache::new(8, head_dim, 10000.0);

    let mut q = vec![1.0f32, 2.0, 3.0, 4.0];
    rope.apply(&mut q, 1, 1, head_dim, 1);

    let c0 = 1.0f32.cos();
    let s0 = 1.0f32.sin();
    let c1 = 0.01f32.cos();
    let s1 = 0.01f32.sin();
    let want = [
        1.0 * c0 - 3.0 * s0,
        2.0 * c1 - 4.0 * s1,
        3.0 * c0 + 1.0 * s0,
        4.0 * c1 + 2.0 * s1,
    ];
    assert_close(&q, &want, "rope_pos1_head4");
}

// ── KV cache overflow — safety ───────────────────────────────────────────────

/// KvCache must saturate at max_len without panicking.
/// Excess push_kv calls are silently ignored; len never exceeds max_len.
#[test]
fn test_kv_cache_saturates_at_max_len() {
    let max_len = 4;
    let num_kv_heads = 2;
    let head_dim = 8;
    let stride = num_kv_heads * head_dim;

    let mut cache = KvCache::new(max_len, num_kv_heads, head_dim);
    let k: Vec<f32> = (0..stride).map(|i| i as f32).collect();
    let v: Vec<f32> = (0..stride).map(|i| i as f32 * 2.0).collect();

    for _ in 0..max_len {
        cache.push_kv(&k, &v);
    }
    assert_eq!(cache.len, max_len, "cache should be full at max_len");

    // These must not panic or corrupt state
    cache.push_kv(&k, &v);
    cache.push_kv(&k, &v);
    assert_eq!(
        cache.len, max_len,
        "cache.len must not exceed max_len after overflow"
    );
}

// ── Quantization — hardcoded ─────────────────────────────────────────────────

#[test]
fn test_quant_matvec_roundtrip() {
    let w: Vec<f32> = (0..16).map(|i| (i as f32 - 7.5) * 0.9).collect();
    let qw = QuantizedWeight::quantize(&w, 4, 4);

    let x = vec![1.0f32, 0.0, 0.0, 0.0];
    let mut y = vec![0.0f32; 4];
    qw.matvec(&x, &mut y);

    let mut dq = vec![0.0f32; 16];
    qw.dequantize_to(&mut dq);
    let expected = &dq[0..4];

    assert_close(&y, expected, "quant_matvec_roundtrip");
}

